import { HttpContextToken } from '@angular/common/http';

/**
 * HttpContextToken to indicate that an error should not trigger a global UI toast.
 * Use this for background verification tasks where failures are expected or handled silently.
 */
export const SILENT_ERROR = new HttpContextToken<boolean>(() => false);

/**
 * HttpContextToken for requests that authenticate themselves (e.g. the reporting
 * backend's body `auth_token`) rather than the shared x-access-token session header.
 * A 401 from such a request reflects that request's own auth, not the CypherView
 * session, so the interceptor must not trigger a global token refresh or forced logout.
 */
export const SKIP_AUTH_REFRESH = new HttpContextToken<boolean>(() => false);
